#include <stdio.h>
int main() {
    // FOR: for(inicio; condição; incremento)
    for (int i = 1; i <= 5; i++) {
        printf("%d ", i);  // exibe: 1 2 3 4 5
    }
    printf("\n");

    // WHILE: repete enquanto condição for verdadeira
    int n = 1;
    while (n <= 3) {
        printf("while: %d\n", n);
        n++;  // n++ é igual a n = n + 1
    }

    // DO-WHILE: executa ao menos uma vez
    int x = 1;
    do {
        printf("do: %d\n", x);
        x++;
    } while (x <= 3);

    return 0;
}

