#include <stdio.h>
int main() {
    // Declaração: tipo nome[tamanho] = {valores};
    int nums[5] = {10, 20, 30, 40, 50};

    // Acesso por índice (começa em 0!)
    printf("%d\n", nums[0]);  // 10 (primeiro)
    printf("%d\n", nums[4]);  // 50 (último)
    // nums[5] seria ERRO! Índice fora do limite

    // Percorrer com for
    for (int i = 0; i < 5; i++) {
        printf("nums[%d] = %d\n", i, nums[i]);
    }

    // Somar todos
    int soma = 0;
    for (int i = 0; i < 5; i++) {
        soma += nums[i];  // soma += x é igual a soma = soma + x
    }
    printf("Soma: %d\n", soma);

    return 0;
}

