#include <stdio.h>
int main() {
    int x = 42;

    // int *ptr = ponteiro para int
    // &x = endereço de memória de x
    int *ptr = &x;

    printf("Valor de x: %d\n", x);       // 42
    printf("Endereço de x: %p\n", &x);   // ex: 0x7fff...
    printf("ptr aponta para: %p\n", ptr); // mesmo endereço
    printf("Valor via ptr: %d\n", *ptr);  // 42 (vai até o endereço)

    // Modificar x através do ponteiro
    *ptr = 100;
    printf("x agora vale: %d\n", x);  // 100!

    return 0;
}

