// CLASSE define atributos (dados) e métodos (comportamentos)
// OBJETO é uma instância da classe (criado com new)

class Carro {
    // Atributos (variáveis da classe)
    String marca;
    int ano;

    // CONSTRUTOR: mesmo nome da classe, sem tipo de retorno
    // this.atributo = distingue atributo do parâmetro
    Carro(String marca, int ano) {
        this.marca = marca;  // this = este objeto
        this.ano = ano;
    }

    // Método da classe
    void descricao() {
        System.out.println(marca + " (" + ano + ")");
    }
}

// Criando objetos com new:
Carro c1 = new Carro("Toyota", 2023);
Carro c2 = new Carro("Honda", 2020);

c1.descricao();  // Toyota (2023)
c2.descricao();  // Honda (2020)

